/**
 * fetchModel - Lấy dữ liệu từ server
 */
function fetchModel(url) {
  // QUAN TRỌNG: Phải có chữ "return" ở đây
  return new Promise((resolve, reject) => {
    console.log("Đang gọi API tới:", url);

    fetch(url)
      .then((response) => {
        if (!response.ok) {
          reject(new Error(`Lỗi HTTP! Trạng thái: ${response.status}`));
        } else {
          return response.json(); // Chuyển đổi sang JSON
        }
      })
      .then((data) => {
        // Resolve với một object chứa thuộc tính data như đề bài yêu cầu
        resolve({ data: data });
      })
      .catch((error) => {
        console.error("Lỗi Fetch:", error);
        reject(error);
      });
  });
}

export default fetchModel;
